DROP TABLE IF EXISTS `medias`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `medias` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `release_date` date DEFAULT NULL,
  `overview` varchar(1000) DEFAULT NULL,
  `poster_path` varchar(200) DEFAULT NULL,
  `media_type` varchar(50) NOT NULL,
  `media_medium` varchar(50) DEFAULT NULL,
  `user_rating` int NOT NULL,
  `public_rating` float DEFAULT NULL,
  `is_dropped` tinyint(1) DEFAULT NULL,
  `is_deleted` tinyint(1) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `external_id` varchar(100) DEFAULT NULL,
  `runtime` int DEFAULT NULL,
  `episodes` int DEFAULT NULL,
  `seasons` int DEFAULT NULL,
  `external_link` varchar(1000) DEFAULT NULL,
  `author` varchar(200) DEFAULT NULL,
  `studio` varchar(200) DEFAULT NULL,
  `external_name` varchar(255) DEFAULT NULL,
  `content_rating_id` int DEFAULT NULL,
  `video_link` varchar(1000) DEFAULT NULL,
  `difficulty` tinyint(1) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `name_UNIQUE` (`name`),
  KEY `release_date_UNIQUE` (`release_date`),
  KEY `media_type_UNIQUE` (`media_type`),
  KEY `user_rating_UNIQUE` (`user_rating`),
  KEY `public_rating_UNIQUE` (`public_rating`),
  KEY `is_deleted_UNIQUE` (`is_deleted`),
  KEY `content_rating_id_UNIQUE` (`content_rating_id`),
  KEY `external_name_UNIQUE` (`external_name`)
) ENGINE=InnoDB AUTO_INCREMENT=1809 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
