INSERT INTO `medias` VALUES (1,'Spider-Man: Homecoming','2017-07-05','Following the events of Captain America: Civil War, Peter Parker, with the help of his mentor Tony Stark, tries to balance his life as an ordinary high school student in Queens, New York City, with fighting crime as his superhero alter ego Spider-Man as a new threat, the Vulture, emerges.','https://image.tmdb.org/t/p/w500/c24sv2weTHPsmDa7jEMN0m2P3RT.jpg','movie',NULL,1,7.34,NULL,NULL,'2017-11-12 00:00:00','2024-02-01 21:47:07','315635',133,NULL,NULL,'https://www.imdb.com/title/tt2250912','John Francis Daley','Marvel Studios','Spider-Man: Homecoming',22,NULL,NULL),(2,'Catwoman','2004-07-22','Liquidated after discovering a corporate conspiracy, mild-mannered graphic artist Patience Phillips washes up on an island, where she\'s resurrected and endowed with the prowess of a cat — and she\'s eager to use her new skills... as a vigilante. Before you can say \"cat and mouse\", handsome gumshoe Tom Lone is on her tail, fascinated by both of her personas.','https://image.tmdb.org/t/p/w500/pvnPgukFyEKgCzyOxyLiwyZ8T1C.jpg','movie',NULL,1,4.594,NULL,NULL,'2016-06-04 00:00:00','2024-02-01 21:47:14','314',104,NULL,NULL,'https://www.imdb.com/title/tt0327554','Pitof','Village Roadshow Pictures','Catwoman',22,NULL,NULL),(3,'The Last Airbender','2010-06-30','The story follows the adventures of Aang, a young successor to a long line of Avatars, who must put his childhood ways aside and stop the Fire Nation from enslaving the Water, Earth and Air nations.','https://image.tmdb.org/t/p/w500/zgwRTYWEEPivTwjB9S03HtmMcbM.jpg','movie',NULL,1,4.654,NULL,NULL,'2016-06-04 00:00:00','2024-02-01 21:47:39','10196',103,NULL,NULL,'https://www.imdb.com/title/tt0938283','Frank Marshall','Paramount','The Last Airbender',21,NULL,NULL),(4,'The Darkest Hour','2011-12-22','In Moscow, five young people lead the charge against an alien race which has attacked Earth via our power supply.','https://image.tmdb.org/t/p/w500/5Ao4qAFbjP7fcFOOdMNvQEnl0Yr.jpg','movie',NULL,2,5.3,NULL,NULL,'2017-08-24 00:00:00','2024-02-01 21:46:47','71469',89,NULL,NULL,'https://www.imdb.com/title/tt1093357','Dmitry Kiselev','Regency Enterprises','The Darkest Hour',22,NULL,NULL),(5,'Ghostbusters','1984-06-08','After losing their academic posts at a prestigious university, a team of parapsychologists goes into business as proton-pack-toting \"ghostbusters\" who exterminate ghouls, hobgoblins and supernatural pests of all stripes. An ad campaign pays off when a knockout cellist hires the squad to purge her swanky digs of demons that appear to be living in her refrigerator.','https://image.tmdb.org/t/p/w500/7E8nLijS9AwwUEPu2oFYOVKhdFA.jpg','movie',NULL,6,7.474,NULL,NULL,'2019-12-19 00:00:00','2024-02-01 21:47:36','620',107,NULL,NULL,'https://www.imdb.com/title/tt0087332','Harold Ramis','Columbia Pictures','Ghostbusters',21,NULL,NULL),(6,'Alvin and the Chipmunks: Chipwrecked','2011-12-14','Playing around while aboard a cruise ship, the Chipmunks and Chipettes accidentally go overboard and end up marooned in a tropical paradise. They discover their new turf is not as deserted as it seems.','https://image.tmdb.org/t/p/w500/7qm7OSNzw57leNtgEizdKVKqyqD.jpg','movie',NULL,2,5.709,NULL,NULL,'2016-06-05 00:00:00','2024-02-01 21:47:00','55301',87,NULL,NULL,'https://www.imdb.com/title/tt1615918','Mike Mitchell','Fox 2000 Pictures','Alvin and the Chipmunks: Chipwrecked',20,NULL,NULL),(7,'Wrath of the Titans','2012-03-28','Perseus tries to live a quieter life as a village fisherman while - dangerously weakened by humanity\'s lack of devotion - the gods are losing control of the long-imprisoned Titans and their ferocious leader, Kronos.','https://image.tmdb.org/t/p/w500/b9n2R3xZWQ8MVZgndQoV34stS0h.jpg','movie',NULL,2,5.725,NULL,NULL,'2016-09-25 00:00:00','2024-02-01 21:47:01','57165',99,NULL,NULL,'https://www.imdb.com/title/tt1646987','Terry Needham','Thunder Road','Wrath of the Titans',22,NULL,NULL),(8,'Snow White and the Huntsman','2012-05-30','After the Evil Queen marries the King, she performs a violent coup in which the King is murdered and his daughter, Snow White, is taken captive. Almost a decade later, a grown Snow White is still in the clutches of the Queen. In order to obtain immortality, The Evil Queen needs the heart of Snow White. After Snow escapes the castle, the Queen sends the Huntsman to find her in the Dark Forest.','https://image.tmdb.org/t/p/w500/8yKdQHaqOo1lkaErmqMuYFespYI.jpg','movie',NULL,2,5.985,NULL,NULL,'2016-06-04 00:00:00','2024-02-01 21:47:02','58595',127,NULL,NULL,'https://www.imdb.com/title/tt1735898','John Lee Hancock','Universal Pictures','Snow White and the Huntsman',22,NULL,NULL),(9,'Pirates of the Caribbean: Dead Men Tell No Tales','2017-05-23','Thrust into an all-new adventure, a down-on-his-luck Capt. Jack Sparrow feels the winds of ill-fortune blowing even more strongly when deadly ghost sailors led by his old nemesis, the evil Capt. Salazar, escape from the Devil\'s Triangle. Jack\'s only hope of survival lies in seeking out the legendary Trident of Poseidon, but to find it, he must forge an uneasy alliance with a brilliant and beautiful astronomer and a headstrong young man in the British navy.','https://image.tmdb.org/t/p/w500/qwoGfcg6YUS55nUweKGujHE54Wy.jpg','movie',NULL,2,6.648,NULL,NULL,'2017-12-29 00:00:00','2024-02-01 21:47:03','166426',128,NULL,NULL,'https://www.imdb.com/title/tt1790809','Joachim Rønning','Walt Disney Pictures','Pirates of the Caribbean: Dead Men Tell No Tales',22,NULL,NULL),(10,'Percy Jackson: Sea of Monsters','2013-08-07','In their quest to confront the ultimate evil, Percy and his friends battle swarms of mythical creatures to find the mythical Golden Fleece and to stop an ancient evil from rising.','https://image.tmdb.org/t/p/w500/tAu90qEpLqwqiZLsMqpaMVr55oN.jpg','movie',NULL,2,6.033,NULL,NULL,'2016-06-04 00:00:00','2024-02-01 21:47:03','76285',106,NULL,NULL,'https://www.imdb.com/title/tt1854564','Chris Columbus','Fox 2000 Pictures','Percy Jackson: Sea of Monsters',21,NULL,NULL),(11,'Miss Peregrine\'s Home for Peculiar Children','2016-09-27','A teenager finds himself transported to an island where he must help protect a group of orphans with special powers from creatures intent on destroying them.','https://image.tmdb.org/t/p/w500/CIlbMFOfYDj0MP23hsIYhFGrL6.jpg','movie',NULL,2,6.825,NULL,NULL,'2016-10-01 00:00:00','2024-02-01 21:47:04','283366',127,NULL,NULL,'https://www.imdb.com/title/tt1935859','Tim Burton','Big Screen Productions','Miss Peregrine\'s Home for Peculiar Children',22,NULL,NULL),(12,'The Smurfs 2','2013-07-30','The evil wizard Gargamel creates a couple of mischievous Smurf-like creatures called the Naughties that he hopes will let him harness the all-powerful, magical Smurf-essence. But when he discovers that only a real Smurf can give him what he wants, and only a secret spell that Smurfette knows can turn the Naughties into real Smurfs, Gargamel kidnaps Smurfette and brings her to Paris, where he has been winning the adoration of millions as the world¹s greatest sorcerer. It\'s up to Papa, Clumsy, Grouchy, and Vanity to return to our world, reunite with their human friends Patrick and Grace Winslow, and rescue her! Will Smurfette, who has always felt different from the other Smurfs, find a new connection with the Naughties Vexy and Hackus or will the Smurfs convince her that their love for her is True Blue?','https://image.tmdb.org/t/p/w500/tmjvgbEH4BKYFfHmWXjXrHgi8wT.jpg','movie',NULL,2,5.757,NULL,NULL,'2017-08-24 00:00:00','2024-02-01 21:47:05','77931',105,NULL,NULL,'https://www.imdb.com/title/tt2017020','Sean Dwyer','NeoReel','The Smurfs 2',21,NULL,NULL),(14,'Insurgent','2015-03-18','Beatrice Prior must confront her inner demons and continue her fight against a powerful alliance which threatens to tear her society apart.','https://image.tmdb.org/t/p/w500/dP5Fb6YRfzmCQtRbHOr2kO7tJW9.jpg','movie',NULL,2,6.364,NULL,NULL,'2016-06-04 00:00:00','2024-02-01 21:47:12','262500',119,NULL,NULL,'https://www.imdb.com/title/tt2908446','Neil Burger','Summit Entertainment','Insurgent',22,NULL,NULL),(15,'Mortdecai','2015-01-21','An art dealer, Charles Mortdecai, searches for a stolen painting rumored to contain a secret code that gains access to hidden Nazi gold.','https://image.tmdb.org/t/p/w500/j7eKGD0n1zRVfKMX6M1kpfavby7.jpg','movie',NULL,2,5.511,NULL,NULL,'2016-09-25 00:00:00','2024-02-01 21:47:13','210860',107,NULL,NULL,'https://www.imdb.com/title/tt3045616','Sue Hills','Lionsgate','Mortdecai',23,NULL,NULL),(16,'The Nice Guys','2016-05-15','A private eye investigates the apparent suicide of a fading porn star in 1970s Los Angeles and uncovers a conspiracy.','https://image.tmdb.org/t/p/w500/uXdQztKoAtx7UU3RvqeF52KsoQP.jpg','movie',NULL,2,7.113,NULL,NULL,'2018-01-05 00:00:00','2025-02-09 21:49:52','290250',116,NULL,NULL,'https://www.imdb.com/title/tt3799694','Luca Kouimelis','Silver Pictures','The Nice Guys',23,NULL,NULL),(17,'Fractured','2019-09-22','Driving cross-country, Ray and his wife and daughter stop at a highway rest area where his daughter falls and breaks her arm. After a frantic rush to the hospital and a clash with the check-in nurse, Ray is finally able to get her to a doctor. While the wife and daughter go downstairs for an MRI, Ray, exhausted, passes out in a chair in the lobby. Upon waking up, they have no record or knowledge of Ray\'s family ever being checked in.','https://image.tmdb.org/t/p/w500/paZNRffT3kUckuRFKbeDBuX1YcZ.jpg','movie',NULL,2,6.716,NULL,NULL,'2020-06-11 00:00:00','2024-02-01 21:47:24','568091',101,NULL,NULL,'https://www.imdb.com/title/tt4332232','Brad Anderson','Koji Productions','Fractured',23,NULL,NULL),(18,'The Smurfs','2011-07-29','When the evil wizard Gargamel chases the tiny blue Smurfs out of their village, they tumble from their magical world and into ours -- in fact, smack dab in the middle of Central Park. Just three apples high and stuck in the Big Apple, the Smurfs must find a way to get back to their village before Gargamel tracks them down.','https://image.tmdb.org/t/p/w500/vRhnslP2gW0QDym7BsMeSuioUfK.jpg','movie',NULL,2,5.761,NULL,NULL,'2016-06-04 00:00:00','2024-02-01 21:47:26','41513',103,NULL,NULL,'https://www.imdb.com/title/tt0472181','Benita Allen','Columbia Pictures','The Smurfs',21,NULL,NULL),(19,'Split','2017-01-19','Though Kevin has evidenced 23 personalities to his trusted psychiatrist, Dr. Fletcher, there remains one still submerged who is set to materialize and dominate all the others. Compelled to abduct three teenage girls led by the willful, observant Casey, Kevin reaches a war for survival among all of those contained within him — as well as everyone around him — as the walls between his compartments shatter apart.','https://image.tmdb.org/t/p/w500/lli31lYTFpvxVBeFHWoe5PMfW5s.jpg','movie',NULL,2,7.338,NULL,NULL,'2017-08-24 00:00:00','2025-02-10 17:54:28','381288',117,NULL,NULL,'https://www.imdb.com/title/tt4972582','M. Night Shyamalan','Universal Pictures','Split',22,NULL,NULL),(20,'Man of Steel','2013-06-12','A young boy learns that he has extraordinary powers and is not of this earth. As a young man, he journeys to discover where he came from and what he was sent here to do. But the hero in him must emerge if he is to save the world from annihilation and become the symbol of hope for all mankind.','https://image.tmdb.org/t/p/w500/dksTL9NXc3GqPBRHYHcy1aIwjS.jpg','movie',NULL,2,6.6,NULL,NULL,'2016-09-25 00:00:00','2024-02-01 21:47:32','49521',143,NULL,NULL,'https://www.imdb.com/title/tt0770828','Christopher Nolan','DC Entertainment','Man of Steel',22,NULL,NULL),(21,'Clash of the Titans','2010-03-26','Born of a god but raised as a man, Perseus is helpless to save his family from Hades, vengeful god of the underworld. With nothing to lose, Perseus volunteers to lead a dangerous mission to defeat Hades before he can seize power from Zeus and unleash hell on earth. Battling unholy demons and fearsome beasts, Perseus and his warriors will only survive if Perseus accepts his power as a god, defies fate and creates his own destiny.','https://image.tmdb.org/t/p/w500/6iHYLipwEyZUPNO8MM3l1yHDaFE.jpg','movie',NULL,2,5.883,NULL,NULL,'2017-08-24 00:00:00','2024-02-01 21:47:33','18823',106,NULL,NULL,'https://www.imdb.com/title/tt0800320','Terry Needham','The Zanuck Company','Clash of the Titans',22,NULL,NULL),(22,'Percy Jackson & the Olympians: The Lightning Thief','2010-02-01','Accident prone teenager, Percy discovers he\'s actually a demi-God, the son of Poseidon, and he is needed when Zeus\' lightning is stolen. Percy must master his new found skills in order to prevent a war between the Gods that could devastate the entire world.','https://image.tmdb.org/t/p/w500/5MgYOWXCKxVlR1MRncrt7kNtCzY.jpg','movie',NULL,2,6.22,NULL,NULL,'2018-07-09 00:00:00','2024-02-01 21:47:34','32657',118,NULL,NULL,'https://www.imdb.com/title/tt0814255','Chris Columbus','1492 Pictures','Percy Jackson & the Olympians: The Lightning Thief',21,NULL,NULL),(23,'Sanctum','2011-02-03','Master diver Frank McGuire has explored the South Pacific\'s Esa-ala Caves for months.  But when his exit is cut off in a flash flood, Frank\'s team—including 17-year-old son Josh and financier Carl Hurley are forced to radically alter plans.  With dwindling supplies, the crew must navigate an underwater labyrinth to make it out.','https://image.tmdb.org/t/p/w500/zRUNv1CbeVtmTCNr6RLHnxV2QYm.jpg','movie',NULL,2,6.043,NULL,NULL,'2017-08-24 00:00:00','2024-02-01 21:47:37','48340',108,NULL,NULL,'https://www.imdb.com/title/tt0881320','James Cameron','Universal Pictures','Sanctum',23,NULL,NULL),(24,'The Happening','2008-06-11','When a deadly airborne virus threatens to wipe out the northeastern United States, teacher Elliott Moore and his wife Alma flee from contaminated cities into the countryside in a fight to discover the truth. Is it terrorism, the accidental release of some toxic military bio weapon -- or something even more sinister?','https://image.tmdb.org/t/p/w500/v1Cw6WaCjNqInpAzUwbXB4LGgoX.jpg','movie',NULL,2,5.395,NULL,NULL,'2016-06-04 00:00:00','2024-02-01 21:47:40','8645',91,NULL,NULL,'https://www.imdb.com/title/tt0949731','M. Night Shyamalan','Dune Entertainment','The Happening',23,NULL,NULL),(25,'Moon','2009-06-12','With only three weeks left in his three year contract, Sam Bell is getting anxious to finally return to Earth. He is the only occupant of a Moon-based manufacturing facility along with his computer and assistant, GERTY. When he has an accident however, he wakens to find that he is not alone.','https://image.tmdb.org/t/p/w500/35IU0Mq0zFsN1mYwDGts5mKc77n.jpg','movie',NULL,3,7.57,NULL,NULL,'2019-01-30 00:00:00','2025-02-10 01:42:52','17431',97,NULL,NULL,'https://www.imdb.com/title/tt1182345','Guy Travers','Lunar Industries','Moon',23,NULL,NULL),(26,'Legend of the Guardians: The Owls of Ga\'Hoole','2010-07-10','When a young owl is abducted by an evil Owl army, he must escape with new-found friends and seek the legendary Guardians to stop the menace.','https://image.tmdb.org/t/p/w500/zKY2nJPozrItOsSCkjgY7QPkLrE.jpg','movie',NULL,3,6.801,NULL,NULL,'2017-08-24 00:00:00','2024-02-01 21:46:53','41216',97,NULL,NULL,'https://www.imdb.com/title/tt1219342','Zack Snyder','Warner Bros. Pictures','Legend of the Guardians: The Owls of Ga\'Hoole',21,NULL,NULL),(28,'Suicide Squad','2016-08-03','From DC Comics comes the Suicide Squad, an antihero team of incarcerated supervillains who act as deniable assets for the United States government, undertaking high-risk black ops missions in exchange for commuted prison sentences.','https://image.tmdb.org/t/p/w500/xFw9RXKZDvevAGocgBK0zteto4U.jpg','movie',NULL,3,5.909,NULL,NULL,'2017-08-24 00:00:00','2024-02-01 21:46:56','297761',123,NULL,NULL,'https://www.imdb.com/title/tt1386697','Zack Snyder','Warner Bros. Pictures','Suicide Squad',22,NULL,NULL),(29,'Now You See Me','2013-05-29','An FBI agent and an Interpol detective track a team of illusionists who pull off bank heists during t